import{_ as o,o as i,c as l,ah as c}from"./chunks/framework.Bi9enVNS.js";const h=JSON.parse('{"title":"能做什么","description":"","frontmatter":{},"headers":[],"relativePath":"intro/capabilities.md","filePath":"intro/capabilities.md","lastUpdated":1774205896000}'),a={name:"intro/capabilities.md"};function d(r,e,t,n,s,u){return i(),l("div",null,[...e[0]||(e[0]=[c('<h1 id="能做什么" tabindex="-1">能做什么 <a class="header-anchor" href="#能做什么" aria-label="Permalink to &quot;能做什么&quot;">​</a></h1><p>这一页只总结当前实现已经具备的能力，不延伸到未来可能会做的方向。</p><h2 id="_1-上传与接入" tabindex="-1">1. 上传与接入 <a class="header-anchor" href="#_1-上传与接入" aria-label="Permalink to &quot;1. 上传与接入&quot;">​</a></h2><ul><li>单一上传入口：<code>POST /v1/logs</code></li><li>支持三种内容类型： <ul><li><code>application/protobuf</code></li><li><code>application/protobuf+json</code></li><li><code>application/json</code></li></ul></li><li>支持 <code>identity</code> 与 <code>gzip</code> 内容编码</li><li>Bearer token 鉴权，并按 token 限定可写入的 project</li><li>批次幂等：幂等键为 <code>project + request_id</code></li><li>记录级拒绝：同一批次可以部分成功、部分失败</li></ul><h2 id="_2-结构化校验" tabindex="-1">2. 结构化校验 <a class="header-anchor" href="#_2-结构化校验" aria-label="Permalink to &quot;2. 结构化校验&quot;">​</a></h2><ul><li>批次级检查 <code>request_id</code>、<code>project</code>、<code>environment</code>、<code>producer.protocol_version</code></li><li>记录级检查 <code>event_time</code>、<code>severity_number</code>、<code>source</code>、<code>trace_id</code>、<code>span_id</code>、<code>trace_flags</code></li><li>单请求记录数上限默认为 <code>1000</code></li><li>解压后请求体大小上限默认为 <code>1 MiB</code></li></ul><h2 id="_3-归一化与建模" tabindex="-1">3. 归一化与建模 <a class="header-anchor" href="#_3-归一化与建模" aria-label="Permalink to &quot;3. 归一化与建模&quot;">​</a></h2><ul><li>把批次默认来源 <code>default_source</code> 与记录级来源 <code>LogRecord.source</code> 合并成有效来源</li><li>生成统一的 <code>NormalizedLogRecord</code></li><li>为每条记录计算 <code>source_fingerprint</code></li><li>把字符串 body 和结构化 body 同时保留为 <code>body_text</code> / <code>body_json</code></li></ul><h2 id="_4-查询接口" tabindex="-1">4. 查询接口 <a class="header-anchor" href="#_4-查询接口" aria-label="Permalink to &quot;4. 查询接口&quot;">​</a></h2><ul><li><code>GET /v1/logs/search</code>：筛选日志</li><li><code>GET /v1/traces/{trace_id}</code>：按 Trace 返回日志流与 span 概览</li><li><code>GET /v1/traces/{trace_id}/timeline</code>：按来源实例聚合时间线泳道</li><li><code>GET /v1/traces/{trace_id}/topology</code>：按来源实例推导节点与边</li><li><code>GET /v1/sources</code>：聚合来源树</li></ul><h2 id="_5-前端可视化" tabindex="-1">5. 前端可视化 <a class="header-anchor" href="#_5-前端可视化" aria-label="Permalink to &quot;5. 前端可视化&quot;">​</a></h2><ul><li>Logs Explorer：筛选并打开 Trace</li><li>Trace Workbench：摘要卡片、拓扑、时间线、检查面板联动</li><li>Sources View：按 <code>source_type -&gt; source_name -&gt; instance_id</code> 浏览来源实例</li><li>前端自身支持中英文界面切换</li></ul><h2 id="_6-示例与演示" tabindex="-1">6. 示例与演示 <a class="header-anchor" href="#_6-示例与演示" aria-label="Permalink to &quot;6. 示例与演示&quot;">​</a></h2><ul><li>线性链路示例</li><li>扇出/汇合示例</li><li>重试回环示例</li><li>消息总线 handoff 示例</li><li><code>make preview</code> / <code>./scripts/dev-preview.sh</code> 一键演示完整流程</li></ul><h2 id="事实来源" tabindex="-1">事实来源 <a class="header-anchor" href="#事实来源" aria-label="Permalink to &quot;事实来源&quot;">​</a></h2><ul><li><code>README.md</code></li><li><code>docs/protocol.md</code></li><li><code>internal/api/http.go</code></li><li><code>internal/ingest/*.go</code></li><li><code>internal/store/*.go</code></li><li><code>web/src/App.jsx</code></li></ul>',16)])])}const p=o(a,[["render",d]]);export{h as __pageData,p as default};
